using System.Drawing;
using System.Text;
using Terminal.Gui.App;
using Terminal.Gui.Drivers;
using Terminal.Gui.ViewBase;
using Terminal.Gui.Views;

StringBuilder log = new ();

static int RequiredWidth (OptionSelector selector)
{
    return selector.SubViews.OfType<CheckBox> ()
                   .Select (cb => cb.Frame.X + cb.Frame.Width)
                   .DefaultIfEmpty (0)
                   .Max ();
}

void AssertFits (string name, OptionSelector selector)
{
    int requiredWidth = RequiredWidth (selector);
    log.AppendLine ($"{name}: selectorWidth={selector.Frame.Width}, requiredWidth={requiredWidth}, content={selector.GetContentSize()}, needsLayout={selector.NeedsLayout}");
    foreach (CheckBox cb in selector.SubViews.OfType<CheckBox> ())
    {
        log.AppendLine ($"  {cb.Title}: {cb.Frame}, margin={cb.Margin.Thickness}");
    }

    if (selector.Frame.Width < requiredWidth)
    {
        throw new InvalidOperationException ($"{name} selector width {selector.Frame.Width} is less than required {requiredWidth}.");
    }
}

using IApplication app = Application.Create ().Init (DriverRegistry.Names.ANSI);

using Window visibleWin = new () { Title = "Visible after empty layout" };
OptionSelector visibleSelector = new () { Y = 2, Orientation = Orientation.Horizontal };
visibleWin.Add (visibleSelector);
SessionToken token = app.Begin (visibleWin)!;
visibleSelector.Labels = ["IMDb (Recommended)", "TMDb"];
visibleSelector.Values = [0, 1];
visibleSelector.Layout (new Size (80, 25));
AssertFits ("visible-after-initial-empty-layout", visibleSelector);
app.End (token);

using Window hiddenWin = new () { Title = "Hidden after empty layout" };
OptionSelector hiddenSelector = new () { Y = 2, Orientation = Orientation.Horizontal, Visible = false };
hiddenWin.Add (hiddenSelector);
token = app.Begin (hiddenWin)!;
hiddenSelector.Labels = ["IMDb (Recommended)", "TMDb"];
hiddenSelector.Values = [0, 1];
hiddenSelector.Visible = true;
hiddenWin.Layout (new Size (80, 25));
AssertFits ("hidden-labels-while-hidden-then-visible", hiddenSelector);
app.End (token);

using Window beforeAddWin = new () { Title = "Labels before add" };
OptionSelector beforeAddSelector = new () { Y = 2, Orientation = Orientation.Horizontal };
beforeAddSelector.Labels = ["IMDb (Recommended)", "TMDb"];
beforeAddSelector.Values = [0, 1];
beforeAddWin.Add (beforeAddSelector);
token = app.Begin (beforeAddWin)!;
AssertFits ("labels-before-add", beforeAddSelector);
app.End (token);

File.WriteAllText ("/tmp/tg-option-repro/out.txt", log.ToString ());
